&lt;h3 dir=&quot;ltr&quot; style=&quot;line-height:1.38;margin-top:14pt;margin-bottom:4pt;&quot;&gt;&lt;span style=&quot;font-size:13pt;font-family:Arial, sans-serif;color:#000000;background-color:transparent;font-weight:bold;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre-wrap;&quot;&gt;Ng&agrave;y 2:&lt;/span&gt;&lt;span style=&quot;font-size:13pt;font-family:Arial, sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre-wrap;&quot;&gt; L&agrave;ng cổ v&agrave; vịnh Lan Hạ&lt;/span&gt;&lt;/h3&gt;
